import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.CMYkYJvz.js";const g=JSON.parse('{"title":"Test Coverage Mechanism","description":"Automatically synced English Test Coverage Mechanism documentation from docs-en/coverage.md.","frontmatter":{"title":"Test Coverage Mechanism","description":"Automatically synced English Test Coverage Mechanism documentation from docs-en/coverage.md.","editLink":false},"headers":[],"relativePath":"en/reference/coverage.md","filePath":"en/reference/coverage.md"}'),r={name:"en/reference/coverage.md"};function n(o,e,l,h,c,d){return t(),a("div",null,[...e[0]||(e[0]=[i(`<blockquote><p>This page is automatically synced from <code>docs-en/coverage.md</code>. Language: <strong>English</strong> | <a href="./../../reference/coverage">中文</a></p></blockquote><h1 id="test-coverage-mechanism" tabindex="-1">Test Coverage Mechanism <a class="header-anchor" href="#test-coverage-mechanism" aria-label="Permalink to &quot;Test Coverage Mechanism&quot;">​</a></h1><p>This document describes how Bifrost measures and enforces test coverage across the <strong>whole test pyramid</strong> — unit tests, integration tests, and end-to-end (E2E) tests — and the workflow for driving every crate to the <strong>90% line coverage</strong> goal.</p><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Measure everything (unit + integration), merge, emit JSON, enforce floors,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    and print exactly where to add tests:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gaps</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Include E2E suites in the merged number:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --with-e2e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gate</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Iterate on a single crate (fast):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-core</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gaps</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Open an HTML report locally:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-core</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --html</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target/coverage/html/index.html</span></span></code></pre></div><h2 id="what-gets-measured" tabindex="-1">What gets measured <a class="header-anchor" href="#what-gets-measured" aria-label="Permalink to &quot;What gets measured&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Source</th><th>How it is captured</th></tr></thead><tbody><tr><td><strong>Unit tests</strong></td><td><code>#[cfg(test)]</code> modules inside each crate</td><td><code>cargo llvm-cov</code> instruments the crate and runs <code>cargo test</code></td></tr><tr><td><strong>Integration tests</strong></td><td><code>crates/bifrost-tests</code> → repo-root <code>tests/*.rs</code></td><td>same <code>cargo llvm-cov</code> run (they are normal test targets)</td></tr><tr><td><strong>E2E tests</strong></td><td><code>scripts/ci/run-e2e-*.sh</code> driving the <code>bifrost</code> + <code>bifrost-e2e</code> binaries</td><td>binaries are built <strong>instrumented</strong>; their <code>.profraw</code> is merged in (<code>--with-e2e</code>)</td></tr></tbody></table><p>All layers write LLVM profile data into the <strong>same</strong> target directory, then a single <code>cargo llvm-cov report</code> merges them. <strong>A line counts as covered if <em>any</em> layer exercises it</strong> — so the merged number reflects the real reach of the whole test suite, which is what the 90% goal is measured against.</p><h2 id="the-mechanism-—-files" tabindex="-1">The mechanism — files <a class="header-anchor" href="#the-mechanism-—-files" aria-label="Permalink to &quot;The mechanism — files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Role</th></tr></thead><tbody><tr><td><code>scripts/ci/coverage-all.sh</code></td><td><strong>Entry point.</strong> Collects unit + integration (+ optional E2E) coverage, merges, emits text/JSON/LCOV/HTML, optionally runs the gate.</td></tr><tr><td><code>scripts/ci/coverage-gate.py</code></td><td><strong>Gate &amp; gap analysis.</strong> Reads the merged JSON, maps files → crates, enforces per-crate + workspace floors, and prints prioritized gaps.</td></tr><tr><td><code>scripts/ci/coverage-thresholds.toml</code></td><td><strong>The contract.</strong> Per-crate line-coverage <em>floors</em> (a ratchet) + the workspace goal. CI fails if coverage drops below a floor.</td></tr><tr><td><code>scripts/ci/coverage.sh</code></td><td>Legacy unit-only helper (still works).</td></tr><tr><td><code>scripts/ci/coverage-e2e.sh</code></td><td>Legacy E2E-only helper (still works).</td></tr></tbody></table><blockquote><p>Prerequisites: <code>rustup component add llvm-tools-preview</code> and <code>cargo install cargo-llvm-cov</code> (the scripts auto-install if missing). On many-core machines the instrumented linker can crash if it spawns one thread per CPU against a small <code>max locked memory</code> ulimit — the scripts therefore constrain build/link parallelism via <code>--jobs</code> (default 4). Override with <code>--jobs N</code> or the <code>COVERAGE_JOBS</code> env var.</p></blockquote><h2 id="the-90-gate-ratchet" tabindex="-1">The 90% gate &amp; ratchet <a class="header-anchor" href="#the-90-gate-ratchet" aria-label="Permalink to &quot;The 90% gate &amp; ratchet&quot;">​</a></h2><p><code>coverage-thresholds.toml</code> declares:</p><ul><li><code>settings.default</code> — the project goal (<strong>90%</strong>), used for any crate without an explicit floor and for the gap report&#39;s target line.</li><li><code>settings.workspace_min</code> — an aggregate floor across the whole workspace.</li><li><code>[crates.&lt;name&gt;].min</code> — a per-crate <strong>floor</strong>. The gate fails if the crate falls below it.</li></ul><p>The floors act as a <strong>ratchet</strong>: they are seeded at the current baseline so CI goes green today, and are raised as tests are added. A floor must never be lowered without explicit justification — that is how the workspace converges on 90% without regressing.</p><h2 id="workflow-driving-a-crate-to-90" tabindex="-1">Workflow: driving a crate to 90% <a class="header-anchor" href="#workflow-driving-a-crate-to-90" aria-label="Permalink to &quot;Workflow: driving a crate to 90%&quot;">​</a></h2><ol><li><p><strong>Find the gaps.</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">crat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gaps</span></span></code></pre></div><p>The gap report lists the files furthest below target, sorted by uncovered-line count (biggest wins first), plus a per-crate &quot;investment priority&quot; total.</p></li><li><p><strong>See which lines are red.</strong> Generate HTML and open the file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">crat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --html</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target/coverage/html/index.html</span></span></code></pre></div></li><li><p><strong>Add targeted tests</strong> for the uncovered branches/functions. Prefer behavior-driven tests over line-chasing; the merged report rewards real integration/E2E coverage too.</p></li><li><p><strong>Re-measure and bump the floor.</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/ci/coverage-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">crat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gate</span></span></code></pre></div><p>Once the crate is ≥ 90%, set its <code>[crates.&lt;crate&gt;].min = 90.0</code> in <code>coverage-thresholds.toml</code> so it can never regress.</p></li><li><p><strong>Repeat</strong> until every crate&#39;s floor is 90 — at which point the floors equal the goal and the workspace is at 90% by construction.</p></li></ol><h2 id="ci-integration" tabindex="-1">CI integration <a class="header-anchor" href="#ci-integration" aria-label="Permalink to &quot;CI integration&quot;">​</a></h2><p>The <code>coverage</code> job in <code>.github/workflows/ci.yml</code>:</p><ol><li>installs <code>llvm-tools-preview</code> + <code>cargo-llvm-cov</code>,</li><li>runs <code>scripts/ci/coverage-all.sh --json --lcov --gate --gaps</code>,</li><li>writes a Markdown summary to the GitHub job summary, and</li><li>uploads <code>coverage.json</code> + <code>lcov.info</code> as artifacts (consumable by Codecov, Coveralls, or local inspection).</li></ol><p>The job <strong>fails the build</strong> if any crate or the workspace aggregate drops below its configured floor. To raise the bar, add tests and bump the floors — never weaken the gate to make it pass.</p>`,21)])])}const k=s(r,[["render",n]]);export{g as __pageData,k as default};
